                                const range = max - min || 1;
                                const points = priceHistory.map((p, i) => `${(i / (priceHistory.length - 1)) * 200},${40 - ((p - min) / range) * 35}`).join(' ');
                                const trend = priceHistory[priceHistory.length - 1] > priceHistory[0] ? 'up' : 'down';
